tests:
def test_set_command():
    state = {}
    inv = Invoker(state)
    inv.execute(SetCommand('x', 42))
    assert state == {'x': 42}

def test_undo_set():
    state = {}
    inv = Invoker(state)
    inv.execute(SetCommand('x', 1))
    inv.undo()
    assert 'x' not in state

def test_delete_command():
    state = {'x': 1}
    inv = Invoker(state)
    inv.execute(DeleteCommand('x'))
    assert 'x' not in state

def test_undo_delete_restores():
    state = {'x': 1}
    inv = Invoker(state)
    inv.execute(DeleteCommand('x'))
    inv.undo()
    assert state == {'x': 1}

def test_redo():
    state = {}
    inv = Invoker(state)
    inv.execute(SetCommand('x', 5))
    inv.undo()
    inv.redo()
    assert state == {'x': 5}

def test_undo_returns_false_when_empty():
    inv = Invoker({})
    assert inv.undo() is False
